using System.Reflection;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.FileProviders;
using TestProject.Services;
using Xunit;

namespace TestProject.Tests;

public class _Probe
{
    [Fact]
    public void Probe()
    {
        var assembly = typeof(_Probe).Assembly;
        var lines = new List<string>();

        // 1. Discover static bool (string,string) methods named TryCreateDirectorySymlink / TryCreateFileSymlink
        foreach (var name in new[] { "TryCreateDirectorySymlink", "TryCreateFileSymlink" })
        {
            foreach (var type in assembly.GetTypes())
            {
                foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static))
                {
                    if (m.Name != name) continue;
                    var ps = m.GetParameters();
                    lines.Add($"FOUND {type.FullName}.{m.Name} static={m.IsStatic} ret={m.ReturnType} params={ps.Length}({string.Join(",", ps.Select(p => p.ParameterType.Name))}) decl={m.DeclaringType.FullName}");
                }
            }
        }

        // 2. Discover FakeWebHostEnvironment types
        foreach (var type in assembly.GetTypes())
        {
            if (type.Name == "FakeWebHostEnvironment" && typeof(IWebHostEnvironment).IsAssignableFrom(type))
            {
                lines.Add($"FAKE_TYPE {type.FullName} nested={type.IsNested} ns={type.Namespace}");
                var inst = Activator.CreateInstance(type, nonPublic: true);
                var env = (IWebHostEnvironment)inst!;
                var crfp = env.ContentRootFileProvider;
                var wrfp = env.WebRootFileProvider;
                lines.Add($"  EnvironmentName=[{env.EnvironmentName}]");
                lines.Add($"  ApplicationName=[{env.ApplicationName}]");
                lines.Add($"  ContentRootPath=[{env.ContentRootPath}]");
                lines.Add($"  ContentRootFileProvider=[{crfp?.GetType().FullName}] isNullFP={crfp is NullFileProvider}");
                lines.Add($"  WebRootPath=[{env.WebRootPath}]");
                lines.Add($"  WebRootFileProvider=[{wrfp?.GetType().FullName}] isNullFP={wrfp is NullFileProvider}");
                lines.Add($"  distinctFP={!ReferenceEquals(crfp, wrfp)}");
            }
        }

        // 3. Discover instance CreateService methods returning (FileService,string)
        var tupleType = typeof((FileService, string));
        foreach (var type in assembly.GetTypes())
        {
            foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static | BindingFlags.Instance))
            {
                if (m.Name != "CreateService") continue;
                if (m.ReturnType != tupleType) continue;
                var ps = m.GetParameters();
                lines.Add($"CREATE_SERVICE {type.FullName}.{m.Name} static={m.IsStatic} ret={m.ReturnType.Name} params={ps.Length}");
            }
        }

        // 4. Probe TryCreateDirectorySymlink swallow behavior on a guaranteed IOException trigger
        //    (link path whose parent dir does not exist -> DirectoryNotFoundException : IOException)
        var fsTestsType = assembly.GetTypes().First(t => t.Name == "FileServiceTests");
        var sl = fsTestsType.GetMethod("TryCreateDirectorySymlink", BindingFlags.NonPublic | BindingFlags.Static)!;
        var badLink = Path.Combine(Path.GetTempPath(), "nonexistent_probe_parent_" + Guid.NewGuid().ToString("N"), "link");
        object? result = null;
        Exception? caught = null;
        try { result = sl.Invoke(null, new object[] { badLink, Path.GetTempPath() }); }
        catch (Exception ex) { caught = ex; }
        lines.Add($"SYMLINK_BAD_PARENT result=[{result}] caught=[{caught?.GetType().Name}] (expect result=False, caught=null)");

        // valid target, capable host
        var tgt = Directory.CreateTempSubdirectory("probe_tgt_").FullName;
        var okLinkDir = Directory.CreateTempSubdirectory("probe_linkparent_").FullName;
        var okLink = Path.Combine(okLinkDir, "linkdir");
        object? r2 = null;
        try { r2 = sl.Invoke(null, new object[] { okLink, tgt }); }
        catch (Exception ex) { caught = ex; }
        lines.Add($"SYMLINK_OK result=[{r2}] linkExists=[{Directory.Exists(okLink)}] caught=[{caught?.GetType().Name}]");

        throw new Exception("PROBE\n" + string.Join("\n", lines));
    }
}

