    public void Probe()
    {
        var fsTestsType = typeof(_SymlinkProbe).Assembly.GetTypes().First(t => t.Name == "FileServiceTests");
        var sl = fsTestsType.GetMethod("TryCreateDirectorySymlink", BindingFlags.NonPublic | BindingFlags.Static)!;

        var parent = Path.Combine(Path.GetTempPath(), "nonexistent_probe_parent_" + Guid.NewGuid().ToString("N"));
