using System.Reflection;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.FileProviders;
using TestProject.Services;
using Xunit;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Characterization tests for the <see cref="FileService"/> test
/// infrastructure that is duplicated across <c>FileServiceTests</c> and
/// <c>FileServiceCharacterizationTests</c>: the <c>CreateService</c> factory,
/// the <c>TryCreateDirectorySymlink</c> / <c>TryCreateFileSymlink</c>
/// reparse-point helpers, and the nested <c>FakeWebHostEnvironment</c> double.
///
/// <para><b>Why discovery-based:</b> a separate task consolidates these
/// byte-identical private members into a single shared helper (mirroring the
/// already-extracted <c>FormFileFactory</c>). Because the members are
/// <c>private</c> today and the shared helper does not exist yet, a test that
/// references the future type directly cannot compile against the current
/// code. Instead these tests <em>discover</em> every implementation of each
/// helper anywhere in the test assembly — by name, signature, return type, or
/// implemented interface — and assert the documented contract against each
/// one. This keeps the suite green before the extraction (finds the private
/// copies) and after it (finds the consolidated shared helper, or the shared
/// helper plus any thin forwarding wrappers the implementer chooses to leave
/// behind), proving the extraction is behavior-preserving regardless of how
/// the call sites are rewired.</para>
///
/// <para>The point of these tests is to catch drift: if a fix to one copy of
/// the symlink exception list, the <c>FakeWebHostEnvironment</c> defaults, or
/// the <c>CreateService</c> root computation is forgotten and applied
/// inconsistently during the extraction, the affected assertion fails. They
/// are the safety net that makes the DRY refactor provably safe.</para>
/// </summary>
public class FileServiceTestInfrastructureTests
{
    private static readonly Assembly TestAssembly = typeof(FileServiceTestInfrastructureTests).Assembly;

    // =====================================================================
    // Discovery helpers
    // =====================================================================

    /// <summary>
    /// Every static <c>bool (string, string)</c> method named
    /// <paramref name="name"/> declared anywhere in the test assembly,
    /// regardless of accessibility or declaring type. Used for the symlink
    /// helpers whose name and signature are preserved across the extraction.
    /// </summary>
    private static IReadOnlyList<MethodInfo> DiscoverStaticSymlinkHelpers(string name)
    {
        var found = new List<MethodInfo>();
        foreach (var type in TestAssembly.GetTypes())
        {
            foreach (var method in type.GetMethods(
                BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static))
            {
                if (method.Name != name)
                {
                    continue;
                }

                var parameters = method.GetParameters();
                if (parameters.Length != 2
                    || parameters[0].ParameterType != typeof(string)
                    || parameters[1].ParameterType != typeof(string)
                    || method.ReturnType != typeof(bool))
                {
                    continue;
                }

                found.Add(method);
            }
        }

        return found;
    }

    /// <summary>
    /// Every type named <c>FakeWebHostEnvironment</c> that implements
    /// <see cref="IWebHostEnvironment"/>, anywhere in the test assembly,
    /// including private nested classes. The type name and implemented
    /// interface are preserved across the extraction (the double merely moves
    /// from a private nested class to a shared public one).
    /// </summary>
    private static IReadOnlyList<Type> DiscoverFakeWebHostEnvironments()
        => TestAssembly.GetTypes()
            .Where(t => t.Name == "FakeWebHostEnvironment"
                && typeof(IWebHostEnvironment).IsAssignableFrom(t))
            .ToList();

    /// <summary>
    /// Every method (instance or static, any accessibility) whose return type
    /// is <c>(<see cref="FileService"/>, string)</c> and whose parameters are
    /// all strings. This is the <c>CreateService</c> factory contract: it
    /// builds a <see cref="FileService"/> and returns it together with the
    /// absolute root it should treat as its sandbox. Discovery is by return
    /// type (not name) because the task explicitly changes the factory's
    /// shape — from a private instance <c>CreateService(string homeDirectory =
    /// "Home")</c> that reads its declaring class's <c>_contentRoot</c>, to a
    /// shared static factory taking the content root as a parameter — so the
    /// name and arity are not stable, but the <c>(FileService, string)</c>
    /// return type is.
    /// </summary>
    private static IReadOnlyList<MethodInfo> DiscoverCreateServiceFactories()
    {
        var tupleType = typeof((FileService, string));
        var found = new List<MethodInfo>();
        foreach (var type in TestAssembly.GetTypes())
        {
            foreach (var method in type.GetMethods(
                BindingFlags.Public | BindingFlags.NonPublic
                | BindingFlags.Static | BindingFlags.Instance))
            {
                if (method.ReturnType != tupleType)
                {
                    continue;
                }

                var parameters = method.GetParameters();
                if (parameters.Length is not (1 or 2)
                    || parameters.Any(p => p.ParameterType != typeof(string)))
                {
                    continue;
                }

                found.Add(method);
            }
        }

        return found;
    }

    // =====================================================================
    // Symlink helpers — existence. The names TryCreateDirectorySymlink and
    // TryCreateFileSymlink are part of the shared contract and must survive
    // the extraction; a botched refactor that drops one without providing the
    // shared equivalent would fail to compile AND fail these guards.
    // =====================================================================

    [Fact]
    public void TryCreateDirectorySymlink_Helper_Exists_In_Test_Assembly()
    {
        Assert.NotEmpty(DiscoverStaticSymlinkHelpers("TryCreateDirectorySymlink"));
    }

    [Fact]
    public void TryCreateFileSymlink_Helper_Exists_In_Test_Assembly()
    {
        Assert.NotEmpty(DiscoverStaticSymlinkHelpers("TryCreateFileSymlink"));
    }

    // =====================================================================
    // Symlink helpers — the swallow-and-return-false contract.
    //
    // These helpers exist precisely to let reparse-point tests opt out cleanly
    // on hosts that cannot create symbolic links (e.g. Windows without the
    // SeCreateSymbolicLinkPrivilege). They MUST return false — never throw —
    // when the underlying CreateSymbolicLink call fails with one of the
    // swallowed exception types (IOException / UnauthorizedAccessException /
    // PlatformNotSupportedException). The most portable, deterministic trigger
    // is a link path whose PARENT directory does not exist: the runtime raises
    // DirectoryNotFoundException, which derives from IOException and is
    // therefore swallowed on every platform. This pins the exception list so a
    // refactor cannot accidentally drop IOException from the catch set.
    // =====================================================================

    public static IEnumerable<object[]> DirectorySymlinkHelpers()
        => DiscoverStaticSymlinkHelpers("TryCreateDirectorySymlink")
            .Select(m => new object[] { m });

    public static IEnumerable<object[]> FileSymlinkHelpers()
        => DiscoverStaticSymlinkHelpers("TryCreateFileSymlink")
            .Select(m => new object[] { m });

    [Theory]
    [MemberData(nameof(DirectorySymlinkHelpers))]
    public void TryCreateDirectorySymlink_ReturnsFalse_WithoutThrowing_WhenLinkParentMissing(MethodInfo method)
    {
        AssertReturnsFalseWithoutThrowing(method, isFileLink: false);
    }

    [Theory]
    [MemberData(nameof(FileSymlinkHelpers))]
    public void TryCreateFileSymlink_ReturnsFalse_WithoutThrowing_WhenLinkParentMissing(MethodInfo method)
    {
        AssertReturnsFalseWithoutThrowing(method, isFileLink: true);
    }

    private static void AssertReturnsFalseWithoutThrowing(MethodInfo method, bool isFileLink)
    {
        // A link path whose parent directory does not exist forces the runtime
        // to throw DirectoryNotFoundException (an IOException) for BOTH
        // directory and file link creation.
        var linkPath = Path.Combine(
            Path.GetTempPath(),
            "nonexistent_probe_parent_" + Guid.NewGuid().ToString("N"),
            isFileLink ? "link.txt" : "linkdir");

        object? result;
        try
        {
            result = method.Invoke(null, new object[] { linkPath, Path.GetTempPath() });
        }
        catch (TargetInvocationException ex)
        {
            // The helper swallowed nothing and let the exception escape.
            Assert.Fail(
                $"{method.DeclaringType?.Name}.{method.Name} was expected to swallow the " +
                $"IOException-class failure and return false, but threw: " +
                $"{ex.InnerException?.GetType().Name}.");
            return; // unreachable; satisfies flow analysis.
        }

        // The helper must return false (not throw) — the swallow contract.
        Assert.False((bool)result!,
            $"{method.DeclaringType?.Name}.{method.Name} must return false (not throw) when the " +
            "link's parent directory is missing.");
    }

    // =====================================================================
    // Symlink helpers — the success path (capable hosts only).
    //
    // On a host that CAN create symbolic links the helper must return true and
    // actually create the link. On a host that cannot (e.g. sandboxed CI), it
    // must return false rather than throw. This assertion verifies the success
    // path is correct WHEN supported, and tolerates unsupported hosts — the
    // same opt-out pattern the production tests use, but pinned here at the
    // helper level so the contract cannot drift.
    // =====================================================================

    [Theory]
    [MemberData(nameof(DirectorySymlinkHelpers))]
    public void TryCreateDirectorySymlink_CreatesLink_OnCapableHost(MethodInfo method)
    {
        AssertCreatesWorkingLinkOnCapableHost(method, isFileLink: false);
    }

    [Theory]
    [MemberData(nameof(FileSymlinkHelpers))]
    public void TryCreateFileSymlink_CreatesLink_OnCapableHost(MethodInfo method)
    {
        AssertCreatesWorkingLinkOnCapableHost(method, isFileLink: true);
    }

    private static void AssertCreatesWorkingLinkOnCapableHost(MethodInfo method, bool isFileLink)
    {
        var target = Directory.CreateTempSubdirectory("probe_tgt_").FullName;
        var parent = Directory.CreateTempSubdirectory("probe_linkparent_").FullName;
        var linkPath = Path.Combine(parent, isFileLink ? "link.txt" : "linkdir");

        try
        {
            // Seed the file-link target with a real file so the link is valid.
            if (isFileLink)
            {
                target = Path.Combine(target, "ignored.txt");
                File.WriteAllText(target, "x");
            }

            var ok = (bool)method.Invoke(null, new object[] { linkPath, target })!;

            if (!ok)
            {
                // Host cannot create symbolic links; the helper correctly
                // returned false. Nothing else to verify, and nothing was
                // created.
                return;
            }

            // On a capable host the link must exist.
            Assert.True(
                isFileLink ? File.Exists(linkPath) : Directory.Exists(linkPath),
                $"{method.DeclaringType?.Name}.{method.Name} returned true but did not create the link at {linkPath}.");
        }
        finally
        {
            if (File.Exists(linkPath))
            {
                try { File.Delete(linkPath); } catch { /* best effort */ }
            }
            if (Directory.Exists(linkPath))
            {
                try { Directory.Delete(linkPath); } catch { /* best effort */ }
            }
            TryDeleteDirectory(parent);
            TryDeleteDirectory(isFileLink ? Directory.GetParent(target)?.FullName! : target);
        }
    }

    // =====================================================================
    // Symlink helpers — cross-implementation agreement. Every discovered copy
    // of each helper must behave identically (the DRY guarantee these tests
    // exist to enforce). They all swallow the IOException-class failure and
    // return false.
    // =====================================================================

    [Fact]
    public void All_TryCreateDirectorySymlink_Copies_ReturnFalseOnFailure()
    {
        var copies = DiscoverStaticSymlinkHelpers("TryCreateDirectorySymlink");
        Assert.NotEmpty(copies);
        var linkPath = Path.Combine(
            Path.GetTempPath(),
            "nonexistent_agree_" + Guid.NewGuid().ToString("N"),
            "linkdir");

        foreach (var method in copies)
        {
            var result = (bool)method.Invoke(null, new object[] { linkPath, Path.GetTempPath() })!;
            Assert.False(result,
                $"{method.DeclaringType?.Name}.{method.Name} disagrees with the others " +
                "(must return false on a missing-parent link path).");
        }
    }

    // =====================================================================
    // FakeWebHostEnvironment — existence. The double's name and the
    // IWebHostEnvironment contract are preserved across the extraction.
    // =====================================================================

    [Fact]
    public void FakeWebHostEnvironment_Type_Exists_In_Test_Assembly()
    {
        Assert.NotEmpty(DiscoverFakeWebHostEnvironments());
    }

    // =====================================================================
    // FakeWebHostEnvironment — the exact default contract.
    //
    // The double is a mutable property bag used to satisfy the
    // IWebHostEnvironment dependency. Its defaults are part of the contract:
    // CreateService only sets ContentRootPath, so every other property must
    // already hold its documented default or downstream behavior (DI,
    // environment-specific code) could change. These assertions pin those
    // defaults so the extraction cannot silently alter them.
    // =====================================================================

    public static IEnumerable<object[]> FakeWebHostEnvironmentTypes()
        => DiscoverFakeWebHostEnvironments().Select(t => new object[] { t });

    [Theory]
    [MemberData(nameof(FakeWebHostEnvironmentTypes))]
    public void FakeWebHostEnvironment_Defaults_MatchTheSharedContract(Type type)
    {
        var env = (IWebHostEnvironment)Activator.CreateInstance(type, nonPublic: true)!;

        Assert.Equal("Development", env.EnvironmentName);
        Assert.Equal("TestProject.Tests", env.ApplicationName);
        Assert.Equal("", env.ContentRootPath);
        Assert.Equal("", env.WebRootPath);
        Assert.IsType<NullFileProvider>(env.ContentRootFileProvider);
        Assert.IsType<NullFileProvider>(env.WebRootFileProvider);
    }

    [Theory]
    [MemberData(nameof(FakeWebHostEnvironmentTypes))]
    public void FakeWebHostEnvironment_PropertiesAreSettable(Type type)
    {
        // CreateService relies on setting ContentRootPath after construction,
        // so the properties must be writable (init-only would break it).
        var env = (IWebHostEnvironment)Activator.CreateInstance(type, nonPublic: true)!;
        var newRoot = Path.Combine(Path.GetTempPath(), "fwe_setter_" + Guid.NewGuid().ToString("N"));

        env.ContentRootPath = newRoot;
        env.EnvironmentName = "Staging";

        Assert.Equal(newRoot, env.ContentRootPath);
        Assert.Equal("Staging", env.EnvironmentName);
    }

    [Fact]
    public void All_FakeWebHostEnvironment_Copies_HaveIdenticalDefaults()
    {
        var copies = DiscoverFakeWebHostEnvironments();
        Assert.NotEmpty(copies);

        // Every discovered copy must report the SAME default snapshot, so a
        // drift in one copy (e.g. a changed ApplicationName) is caught.
        string Snapshot(IWebHostEnvironment e)
            => $"{e.EnvironmentName}|{e.ApplicationName}|{e.ContentRootPath}|{e.WebRootPath}"
                + $"|{e.ContentRootFileProvider?.GetType().Name}|{e.WebRootFileProvider?.GetType().Name}";

        var first = Snapshot((IWebHostEnvironment)Activator.CreateInstance(copies[0], nonPublic: true)!);
        foreach (var type in copies)
        {
            var env = (IWebHostEnvironment)Activator.CreateInstance(type, nonPublic: true)!;
            Assert.Equal(first, Snapshot(env));
        }
    }

    // =====================================================================
    // CreateService factory — the root-computation and wiring contract.
    //
    // The factory builds a FileService whose home directory lives under a
    // content root and returns the absolute, normalized root the service
    // should treat as its sandbox:
    //   root = Path.GetFullPath(Path.Combine(contentRoot, homeDirectory))
    // wired through a FakeWebHostEnvironment (ContentRootPath = contentRoot)
    // and FileServiceOptions (HomeDirectory = homeDirectory). This pins that
    // computation and confirms the produced service actually resolves its
    // root through the public surface — the behavior the ~100 FileService
    // tests depend on, but asserted here at the factory level so the
    // extraction cannot rewire env/options or miscompute the root.
    // =====================================================================

    [Fact]
    public void CreateService_Factory_ComputesRoot_AndProducesWorkingService()
    {
        var factories = DiscoverCreateServiceFactories();
        Assert.NotEmpty(factories);

        var verified = 0;
        foreach (var method in factories)
        {
            var invocation = BuildFactoryInvocation(method, homeDirectory: "ProbeHome");
            if (invocation is null)
            {
                // Factory shape this characterization does not drive (e.g. an
                // arity this test does not construct); still discovered for the
                // existence guard above.
                continue;
            }

            try
            {
                var returned = (ValueTuple<FileService, string>)method.Invoke(
                    invocation.Instance, invocation.Args)!;
                var service = returned.Item1;
                var root = returned.Item2;

                var expectedRoot = Path.GetFullPath(
                    Path.Combine(invocation.ContentRoot, "ProbeHome"));

                Assert.Equal(expectedRoot, root);
                // ResolveFullPath triggers lazy home-root creation and must
                // report the same absolute root the factory returned,
                // proving the service is wired to the right env/options.
                Assert.Equal(expectedRoot, service.ResolveFullPath(""));
                Assert.True(Directory.Exists(expectedRoot));

                verified++;
            }
            finally
            {
                invocation.Dispose();
            }
        }

        // The characterization is non-vacuous: at least one discovered factory
        // was actually exercised against the contract.
        Assert.True(verified > 0,
            "No CreateService factory was verified against the root-computation contract; " +
            "discovery found shapes this test does not drive.");
    }

    /// <summary>
    /// Builds the reflection arguments needed to invoke a discovered
    /// <c>CreateService</c>-style factory, supporting both the pre-extraction
    /// shape (private instance method taking a single home-directory argument
    /// and reading its declaring class's <c>_contentRoot</c>) and the
    /// post-extraction shape (shared static factory taking
    /// <c>(contentRoot, homeDirectory)</c>). Returns null for shapes this
    /// characterization does not drive.
    /// </summary>
    private static FactoryInvocation? BuildFactoryInvocation(MethodInfo method, string homeDirectory)
    {
        var parameters = method.GetParameters();

        if (parameters.Length == 1 && !method.IsStatic)
        {
            // Current shape: private instance CreateService(string home) using _contentRoot.
            var instance = Activator.CreateInstance(method.DeclaringType!, nonPublic: true);
            var field = method.DeclaringType!
                .GetField("_contentRoot", BindingFlags.NonPublic | BindingFlags.Instance);
            if (field is null || instance is null)
            {
                return null;
            }

            var contentRoot = (string)field.GetValue(instance)!;
            return new FactoryInvocation(
                contentRoot,
                Instance: instance,
                Args: new object[] { homeDirectory },
                OwnedInstance: instance as IDisposable,
                OwnedTempDir: null);
        }

        if (parameters.Length == 2)
        {
            // Future shape: static (or instance) factory taking
            // (contentRoot, homeDirectory).
            var contentRoot = Directory.CreateTempSubdirectory("probe_factory_").FullName;
            object? instance = method.IsStatic
                ? null
                : Activator.CreateInstance(method.DeclaringType!, nonPublic: true);

            return new FactoryInvocation(
                contentRoot,
                Instance: instance,
                Args: new object[] { contentRoot, homeDirectory },
                OwnedInstance: instance as IDisposable,
                OwnedTempDir: contentRoot);
        }

        return null;
    }

    private sealed record FactoryInvocation(
        string ContentRoot,
        object? Instance,
        object[] Args,
        IDisposable? OwnedInstance,
        string? OwnedTempDir)
    {
        public void Dispose()
        {
            (OwnedInstance as IDisposable)?.Dispose();
            if (OwnedTempDir is not null)
            {
                TryDeleteDirectory(OwnedTempDir);
            }
        }
    }

    private static void TryDeleteDirectory(string path)
    {
        try
        {
            if (Directory.Exists(path))
            {
                Directory.Delete(path, recursive: true);
            }
        }
        catch
        {
            // Best-effort cleanup of scratch directories created during discovery.
        }
    }
}

