using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Services;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Shared test infrastructure for <see cref="FileService"/> tests.
///
/// <para>
/// This consolidates the byte-identical private copies of the
/// <c>CreateService</c> factory, the <c>TryCreateDirectorySymlink</c> /
/// <c>TryCreateFileSymlink</c> reparse-point helpers, and the
/// <see cref="FakeWebHostEnvironment"/> double that were previously duplicated
/// across <c>FileServiceTests</c> and <c>FileServiceCharacterizationTests</c>.
/// Each test class owns its own per-test temporary content root, so the
/// factory takes the content root as an explicit parameter. This mirrors the
/// project's existing convention of extracting shared test helpers, e.g.
/// <see cref="FormFileFactory"/>.
/// </para>
/// </summary>
public static class FileServiceTestFactory
{
    /// <summary>
    /// Builds a fresh <see cref="FileService"/> whose home directory lives
    /// under <paramref name="contentRoot"/> and returns the absolute,
    /// normalized root the service should treat as its sandbox:
    /// <c>Path.GetFullPath(Path.Combine(contentRoot, homeDirectory))</c>.
    /// </summary>
    /// <param name="contentRoot">
    /// The per-test temporary content root (each test class owns its own
    /// <c>_contentRoot</c>).
    /// </param>
    /// <param name="homeDirectory">
    /// The configured home directory, combined with the content root to form
    /// the sandbox root. Defaults to <c>"Home"</c>.
    /// </param>
    /// <returns>
    /// The constructed service and the absolute root it resolves paths
    /// against.
    /// </returns>
    public static (FileService service, string root) CreateService(
        string contentRoot,
        string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(contentRoot, homeDirectory));
        return (service, root);
    }

    /// <summary>
    /// Creates a directory symbolic link, returning <c>false</c> when the host
    /// cannot create one (e.g. Windows without the SeCreateSymbolicLinkPrivilege)
    /// so reparse-point-skipping tests can opt out cleanly instead of failing.
    /// </summary>
    public static bool TryCreateDirectorySymlink(string linkPath, string target)
    {
        try
        {
            return Directory.CreateSymbolicLink(linkPath, target) is not null;
        }
        catch (IOException) { return false; }
        catch (UnauthorizedAccessException) { return false; }
        catch (PlatformNotSupportedException) { return false; }
    }

    /// <summary>
    /// File-symlink counterpart of <see cref="TryCreateDirectorySymlink"/>.
    /// </summary>
    public static bool TryCreateFileSymlink(string linkPath, string target)
    {
        try
        {
            return File.CreateSymbolicLink(linkPath, target) is not null;
        }
        catch (IOException) { return false; }
        catch (UnauthorizedAccessException) { return false; }
        catch (PlatformNotSupportedException) { return false; }
    }
}

/// <summary>
/// Minimal <see cref="IWebHostEnvironment"/> double used to satisfy the
/// <see cref="FileService"/> dependency. Only
/// <see cref="IWebHostEnvironment.ContentRootPath"/> is meaningful for these
/// tests; the remaining properties carry their documented defaults.
/// </summary>
public sealed class FakeWebHostEnvironment : IWebHostEnvironment
{
    public string EnvironmentName { get; set; } = "Development";
    public string ApplicationName { get; set; } = "TestProject.Tests";
    public string ContentRootPath { get; set; } = "";
    public IFileProvider ContentRootFileProvider { get; set; } = new NullFileProvider();
    public string WebRootPath { get; set; } = "";
    public IFileProvider WebRootFileProvider { get; set; } = new NullFileProvider();
}

